import React, { useEffect } from 'react';
import { useForm, useFormContext, SubmitHandler } from 'react-hook-form';
import { Button, TextField } from '@mui/material';
import { Select, MenuItem, InputLabel, FormControl } from '@mui/material';
import { BrowserRouter as Router, Route, Routes, Link } from 'react-router-dom';
import { yupResolver } from '@hookform/resolvers/yup';
import { useNavigate } from 'react-router-dom';
import { firstFormSchema } from '../yupSchema';
import { useDispatch } from 'react-redux';
// import { updateUserExtraData } from '../redux/userSlice';

interface FormData {
  address: string;
  state: any;
  city: string;
  country: string;
  pinCode: number;
}

interface FirstFormProps {
  onSubmit: (data: any) => Promise<void>;
}

interface Country {
  name: {
    common: string;
    official: string;
  };
}

const SecondForm: React.FC<FirstFormProps> = (props) => {
  const [countries, setCountries] = React.useState<Country[]>([]);
  const [selectedCountry, setSelectedCountry] = React.useState('');
  const methods = useForm<FormData>({
    resolver: yupResolver(firstFormSchema) as any,
  });

  useEffect(() => {
    const fetchCountries = async () => {
      try {
        const response = await fetch('https://restcountries.com/v3.1/all');
        const data = await response.json();
        setCountries(data);
      } catch (error) {
        console.error('Error fetching countries:', error);
      }
    };

    fetchCountries();
  }, []);
  console.log('countries', countries);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = methods;
  const navigate = useNavigate();
  const dispatch = useDispatch();

  const onSubmit: SubmitHandler<FormData> = async (data: FormData) => {
    console.log('data', data);
    console.log('methods', methods.handleSubmit);
    console.log('errors', errors);
    dispatch(updateUserExtraInfo(data));
  };

  return (
    <div className="container">
      <h4>Address Details</h4>
      <form
        onSubmit={handleSubmit(onSubmit)}
        // className="form"
      >
        <div className="form">
          <div className="form-group">
            <div className="label">Addess*</div>
            <TextField
              placeholder="Enter Address"
              type="text"
              {...register('address')}
            />
            {errors.address && (
              <div className="error">{errors.address.message}</div>
            )}
          </div>
          <div className="form-group">
            <div className="label">State</div>
            <TextField
              placeholder="Enter State"
              type="text"
              {...register('state')}
            />
            {errors.state && (
              <div className="error">{(errors.state as any).message}</div>
            )}
          </div>
          <div className="form-group">
            <div className="label">City</div>
            <TextField
              placeholder="Enter City/Town/Village"
              type="text"
              {...register('city')}
            />
            {errors.city && (
              <div className="error">{(errors.city as any).message}</div>
            )}
          </div>
        </div>
        <div className="form">
          <div className="form-group">
            <div className="label">Country</div>
            <FormControl fullWidth>
              <Select
                labelId="country-label"
                id="country"
                value={selectedCountry}
                onChange={(event) => setSelectedCountry(event.target.value)}
              >
                {countries.map((country) => (
                  <MenuItem key={'country'} value={country.name.common}>
                    {country.name.common}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </div>
          <div className="form-group">
            <div className="label">Pin Code</div>
            <TextField
              placeholder="Enter Pind Code"
              {...register('pinCode')}
              type="number"
            />
            {errors.pinCode && (
              <div className="error">{errors.pinCode.message}</div>
            )}
          </div>
        </div>

        <Button className="btn" type="submit">
          Submit
        </Button>
      </form>
    </div>
  );
};

export default SecondForm;
